class FitnessTracker:
    def __init__(self):
     self.activities = {}  # public attributes for storing activities
     self.__user_id= None     # private attributes for user ID

    def add_activity(self,activity_type, duration):
        self.activities[activity_type] = duration  # Add or update activity duration

    def remove_activity(self,activity_type):
     if activity_type in self.activities:
         del self.activities[activity_type]  # Remove specified activity Type
     else:
         print("Activity not found")

    def calculate_calories_burned(self):
       total_calories = sum(duration * 5 for duration in self.activities.values())
       return total_calories

    def display_activities(self):
        return {activity: duration for activity,duration in self.activities.items()}

    def set_user_id(self, new_user_id):
        self.__user_id = new_user_id

    def get_user_id(self):
        return self.__user_id 

